  ('IntexGlobal','5021','Discovery 6 Panel Brushed Cotton Baseball Cap','discovery-6-panel-brushed-cotton-baseball-cap-5021','Headwear','Caps','Introducing the Discovery 6 Panel Brushed Cotton Baseball Cap, made from soft brushed cotton for a comfortable and classic fit. Designed for everyday wear, uniforms, or events, it features a structured crown, pre-curved visor, and adjustable strap for a secure and customizable fit.',25,true,false,'["Eyelets: 6 Embroidered Eyelets for Ventilation."]'::jsonb,'[{"name": "Closure", "value": "Velcro Strap Closure."}, {"name": "Fabric/Material", "value": "100% Brushed Cotton."}, {"name": "Profile", "value": "Mid Profile."}, {"name": "Panels", "value": "6 Panels."}, {"name": "Visor", "value": "Pre-curved Visor."}, {"name": "Structured", "value": "Structured Front Panels."}, {"name": "Size", "value": "One Size Fits All."}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5021/5021-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5021/5021-navy.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5021/5021-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/discovery/');
