  ('IntexGlobal','5101','Colorado Backpack Tote Bag','colorado-backpack-tote-bag-5101','Bags','Tote Bags','The Colorado Backpack is designed for those who demand practicality, durability, and eco-consciousness in their gear. Whether navigating the urban jungle or exploring the great outdoors, this 45-litre backpack has you covered.',10,true,false,'["Eco-Friendly Construction: Made from recycled materials, supporting sustainability.", "Spacious 45L Capacity: Ideal for carrying all your essentials for work, travel, or outdoor activities.", "Integrated Rain Cover: Provides reliable protection against unexpected weather.", "Secure Laptop Storage: Padded compartment fits laptops up to 16” with a suspended cradle for added protection.", "Tablet Slot and Soft-Lined Pocket: Dedicated spaces for tablets, phones, or sunglasses.", "Smart Organization: Multi-compartment design includes a built-in organizer with storage pouches, pen holders, zippered pocket, and key clip.", "Travel-Friendly Features: Equipped with a travel sleeve and a concealed RFID protection pocket for security on the go.", "Quick-Access Hip Pocket: Convenient storage for small items like snacks or keys.", "Safety Features: Reflective trim enhances visibility in low light conditions.", "Side Bottle Pocket: Holds bottles or beverages for hydration on the move.", "Water-Resistant Fabric: Built to withstand various weather conditions."]'::jsonb,'[{"name": "Size", "value": "38cm W x 53cm H x 28cm D"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5101/5101-black.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/colorado-backpack/');
insert into products (supplier, supplier_sku, name, slug, category, subcategory, description, min_qty, is_published, is_eco, features, specs, colours, decoration_model, decoration_source, decoration_required, quote_only, quote_ref_price, lead_time_days, fulfillment, brand, supplier_url) values
  ('IntexGlobal','5102','Fitzroy Backpack Tote Bag','fitzroy-backpack-tote-bag-5102','Bags','Tote Bags','The Fitzroy Backpack is the ideal companion for professionals and adventurers seeking functionality, style, and reliability. With a 34-litre capacity and smart organizational features, this backpack is designed to keep you comfortable and prepared, wherever your day takes you.',10,true,false,'["Padded Laptop Sleeve: Fits laptops up to 17 inches, accessible through an easy-to-reach back zipper.", "Organizer Compartment: Includes multiple pockets, a zippered mesh pocket, and a built-in key fob for convenient storage.", "Media Player Pocket: Secure and accessible compartment for your gadgets.", "Valuables Pocket: Dedicated space for smartphones or other small essentials.", "Side Mesh Water Bottle Pocket: Keeps hydration within easy reach.", "Ergonomic Shoulder Straps: S-shaped mesh shoulder straps with padding, a suspension system, thumb-ring pulls, and a cell phone pocket for ultimate comfort and utility.", "Mesh Grab Handle: Durable and comfortable for quick carrying.", "Padded Back Panel: Provides superior comfort and support, with a tuck-away waist belt for added stability when needed.", "Spacious Main Compartment: Offers approximately 34 litres of capacity, perfect for work, travel, or outdoor adventures."]'::jsonb,'[{"name": "Size", "value": "33cm(w) x 48cm(h) x 21.9cm(d)"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5102/5102-black.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/fitzroy-backpack/');
insert into products (supplier, supplier_sku, name, slug, category, subcategory, description, min_qty, is_published, is_eco, features, specs, colours, decoration_model, decoration_source, decoration_required, quote_only, quote_ref_price, lead_time_days, fulfillment, brand, supplier_url) values
  ('IntexGlobal','5103','Eiger Backpack Tote Bag','eiger-backpack-tote-bag-5103','Bags','Tote Bags','The Eiger Backpack is the ultimate companion for travelers, commuters, and students who value efficiency and convenience. With its checkpoint-friendly features and robust design, this 42-litre backpack ensures you stay organized and ready for any adventure.',10,true,false,'["Durable Material: Made from rugged 600D PolyCanvas for enhanced durability and long-lasting use.", "Spacious Design: Offers four compartments for easy organization and ample storage space.", "Checkpoint-Friendly Layout: Designed to simplify airport security checks, making travel hassle-free.", "Padded Laptop Compartment: Fits laptops up to 17 inches with extra cushioning for protection.", "Dedicated Tablet Sleeve: A secure space for iPads or other tablets.", "Organizer Section: Includes a mesh pocket, pen holders, and a built-in key clip to keep essentials in place.", "Side Water Bottle Pocket: Convenient access to hydration while on the go.", "Generous Capacity: Main compartment provides approximately 42 litres of storage, perfect for work, travel, or school."]'::jsonb,'[{"name": "Size", "value": "41cm(w) x 54cm(h) x 23cm(d)"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5103/5103-black.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/eiger-backpack/');
