  ('IntexGlobal','5104','Blackburn Backpack Tote Bag','blackburn-backpack-tote-bag-5104','Bags','Tote Bags','The Blackburn Backpack is a stylish and functional backpack designed for work, travel, and everyday use. With a padded laptop sleeve, multiple organizer pockets, and a USB charging port, this backpack ensures convenience, comfort, and efficiency for professionals, students, and commuters.',10,true,false,'["Durable Polyester Material: Designed for long-lasting use and everyday wear.", "Padded Laptop Sleeve: Provides secure storage for laptops, keeping them protected.", "USB Charging Port: Convenient for on-the-go charging (power bank not included).", "Multiple Organizer Pockets: Includes two small pockets & two pen holders.", "Front Zippered Pouch: Offers quick access to small items.", "Adjustable Straps: Ensures a comfortable fit for all-day carrying.", "Spacious Interior: Ideal for work, travel, or school essentials."]'::jsonb,'[{"name": "Size", "value": "29cm W x 42cm H x 12 cm D"}, {"name": "Capacity", "value": "15L"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/5104/5104-black.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/blackburn-backpack/');
