  ('IntexGlobal','AUTO03','Helios Foldable Car Sun Visor Car Accessory','helios-foldable-car-sun-visor-car-accessory-auto03','Tools & Auto','Car Accessories','The Helios Foldable Car Sun Visor is a trendy and functional automotive accessory, designed to keep your car interior cooler while protecting it from harmful UV rays. Made from durable polyester material, this visor is lightweight, foldable, and easy to store, making it a versatile and effective promotional giveaway for car owners.',250,true,false,'["Durable Polyester Material: Helps reduce heat buildup inside the car.", "Universal Fit: Suitable for any car model.", "Foldable & Compact Design: Easily folds down for convenient storage when not in use.", "Easy to Install & Remove: Simple setup with no extra tools required.", "Perfect for Sun Protection: Shields the dashboard and seats from UV rays and heat damage."]'::jsonb,'[{"name": "Size", "value": "70 (w) x 150 (h) cm"}]'::jsonb,'[{"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/auto03/auto03-main.webp"}]'::jsonb,null,'supplier',true,true,2.47,28,'indent_sea','Intex','https://www.intexglobal.com/product/foldable-car-sun-visor/');
insert into products (supplier, supplier_sku, name, slug, category, subcategory, description, min_qty, is_published, is_eco, features, specs, colours, decoration_model, decoration_source, decoration_required, quote_only, quote_ref_price, lead_time_days, fulfillment, brand, supplier_url) values
  ('IntexGlobal','AUTO06','Shadex Foldable Car Sunshade Car Accessory','shadex-foldable-car-sunshade-car-accessory-auto06','Tools & Auto','Car Accessories','The Shadex Foldable Car Sunshade is a practical and easy-to-use solution to keep your car cool and protected from the sun. Made from high-quality foil-style polyester, it reflects sunlight and heat effectively. The foldable design with an elastic strap makes it convenient to store when not in use.',250,true,false,'["Foil-Style Sunshade – Reflects sunlight to reduce interior heat", "High-Quality Polyester – Durable and long-lasting material", "Foldable Design – Easily folds onto itself for compact storage", "Elastic Strap – Keeps it neatly secured when folded", "Universal Fit – Suitable for most car windshields"]'::jsonb,'[{"name": "Size", "value": "69 (h) x 130 (w) cm"}]'::jsonb,'[{"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/auto06/auto06-main.webp"}]'::jsonb,null,'supplier',true,true,2.39,28,'indent_sea','Intex','https://www.intexglobal.com/product/foldable-car-sunshade/');
insert into products (supplier, supplier_sku, name, slug, category, subcategory, description, min_qty, is_published, is_eco, features, specs, colours, decoration_model, decoration_source, decoration_required, quote_only, quote_ref_price, lead_time_days, fulfillment, brand, supplier_url) values
  ('IntexGlobal','AUTO21','Astro Side Window Car Sunshade Car Accessory','astro-side-window-car-sunshade-car-accessory-auto21','Tools & Auto','Car Accessories','The Side Window Car Sunshade is a practical and effective accessory designed to reduce glare, block UV rays, and keep car interiors cooler. Featuring PVC suction cups for a secure hold, this lightweight and foldable sunshade is easy to install, remove, and store, making it a great promotional giveaway for car owners.',250,true,false,'["UV Protection & Heat Reduction: Helps shield passengers from sun exposure.", "Durable & Lightweight Material: Made for long-lasting use.", "Foldable & Portable Design: Easily folds for convenient storage.", "Easy Installation: Secures to windows with strong PVC suction cups.", "Universal Fit: Suitable for most vehicle side windows.", "Custom Branding Available: Can be printed with logos or designs for promotional use."]'::jsonb,'[{"name": "Size", "value": "36 (w) x 47 (h) cm"}]'::jsonb,'[{"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/auto21/auto21-main.webp"}]'::jsonb,null,'supplier',true,true,1.42,28,'indent_sea','Intex','https://www.intexglobal.com/product/side-window-car-sunshade/');
