  ('IntexGlobal','CALB20','Coloured Cotton Tote Cotton Tote Bag','coloured-cotton-tote-cotton-tote-bag-calb20','Bags','Cotton Tote Bags','The Coloured Cotton Tote is a premium promotional bag designed for everyday use, combining durability, functionality, and vibrant colour options. Perfect for events, retail, and eco-conscious branding.',250,true,false,'["Durable 180gsm Cotton Fabric: Strong and reusable, offering a sustainable alternative to plastic bags.", "Long Handles: Designed for comfortable shoulder carrying.", "Velcro Closure: Secures the top of the bag, keeping contents protected.", "Available in a Wide Range of Colours: Perfect for matching brand aesthetics or promotional themes.", "Large Branding Area: Ideal for printing logos, slogans, or custom designs for maximum brand exposure.", "Eco-Friendly & Reusable: A stylish and sustainable choice for businesses looking to reduce environmental impact."]'::jsonb,'[{"name": "Size", "value": "38 (w) x 42 (h) cm"}]'::jsonb,'[{"name": "Light Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/calb20/calb20-light-blue.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/calb20/calb20-navy.webp"}, {"name": "Olive", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/calb20/calb20-olive.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/calb20/calb20-red.webp"}, {"name": "Sand", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/calb20/calb20-sand.webp"}]'::jsonb,null,'supplier',true,true,2.05,28,'indent_sea','Intex','https://www.intexglobal.com/product/coloured-cotton-tote/');
