  ('IntexGlobal','COLB01','Perisher Cooler Bag','perisher-cooler-bag-colb01','Bags','Cooler Bags','The Perisher Cooler Bag is a practical and durable promotional item, designed to keep food and beverages fresh while providing excellent branding opportunities. Ideal for picnics, outdoor events, and corporate giveaways.',250,true,false,'["Large Insulated Interior: Lined with EVA material for superior temperature retention.", "Durable 80gsm Non-Woven Exterior: Lightweight yet sturdy for everyday use.", "Zip Closure: Ensures secure storage and helps maintain insulation.", "Spacious Design: Perfect for carrying food, drinks, and snacks for outdoor activities.", "Eco-Friendly & Reusable: A sustainable alternative to disposable coolers.", "Large Branding Area: Ideal for printing logos, slogans, or promotional designs."]'::jsonb,'[{"name": "Size", "value": "31 (w) x 32 (h) x 21 (d) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-royal.webp"}]'::jsonb,null,'supplier',true,true,1.89,28,'indent_sea','Intex','https://www.intexglobal.com/product/perisher-cooler-bag/');
insert into products (supplier, supplier_sku, name, slug, category, subcategory, description, min_qty, is_published, is_eco, features, specs, colours, decoration_model, decoration_source, decoration_required, quote_only, quote_ref_price, lead_time_days, fulfillment, brand, supplier_url) values
  ('IntexGlobal','COLB03','Smiggins Cooler Bag','smiggins-cooler-bag-colb03','Bags','Cooler Bags','The Smiggins Cooler Bag is a lightweight and practical 6-can cooler, perfect for keeping drinks and snacks fresh while on the go. Its compact design and adjustable strap make it ideal for outdoor events, corporate promotions, and giveaways.',250,true,false,'["Durable 210D Nylon Material: Strong yet lightweight for everyday use.", "Holds Up to 6 Cans: Perfect for carrying beverages, snacks, or small meals.", "Adjustable Webbed Carry Strap: Ensures comfortable and easy transportation.", "Secure Zip Closure: Helps maintain insulation and freshness.", "Available in Multiple Colours: Choose from a variety of fabric shades to match your brand.", "Large Branding Area: Ideal for printing logos, event names, or promotional messages."]'::jsonb,'[{"name": "Size", "value": "21 (w) x 20 (h) x 16 (d) cm"}]'::jsonb,'[{"name": "Burgundy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-burgundy.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w4