  ('IntexGlobal','DUFB33','Economy Duffle Bag','economy-duffle-bag-dufb33','Bags','Drawstring Bags','The Economy Duffle Bag is a cost-effective and practical promotional item, ideal for giveaways, events, and everyday use. Made from 170D nylon, this bag is lightweight yet durable, providing a functional and reusable alternative to plastic bags.',250,true,true,'["Durable 170D Nylon Material: Lightweight yet strong for carrying essentials.", "Drawstring Closure: Securely holds items while allowing easy access.", "Spacious Interior: Perfect for gym gear, travel essentials, or event giveaways.", "Available in Multiple Colours: Customizable to match brand identity and promotional themes.", "Eco-Friendly & Reusable: A sustainable and long-lasting alternative to disposable bags.", "Large Branding Area: Ideal for printing logos, slogans, or promotional designs for maximum visibility."]'::jsonb,'[{"name": "Size", "value": "34 (w) x 29 (h)  cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/dufb33/dufb33-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/dufb33/dufb33-blue.webp"}, {"name": "Forest Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/dufb33/dufb33-forest-green.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/dufb33/dufb33-grey.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/dufb33/dufb33-pink.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/dufb33/dufb33-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d