  ('IntexGlobal','FOLB01','Melbourne Foldable Bag With Gusset','melbourne-foldable-bag-with-gusset-folb01','Bags','Tote Bags','The Melbourne Foldable Bag with Gusset is a practical and sustainable reusable shopping bag, designed for convenience and portability. Made from durable 190T nylon, this bag easily folds down to a compact size, making it ideal for everyday use and promotional giveaways.',250,true,false,'["Durable 190T Nylon Material: Strong, lightweight, and reusable for long-term use.", "Foldable Design: Easily folds down to pocket size and secures with an elastic band for effortless storage.", "Gusseted Base: Provides extra space for carrying groceries, retail items, or everyday essentials.", "Large Branding Area: Perfect for screen printing logos, slogans, or promotional messages.", "Versatile Use: Ideal for shopping, trade shows, corporate giveaways, and eco-conscious promotions."]'::jsonb,'[{"name": "Size", "value": "30 (w) x 35 (h) cm"}]'::jsonb,'[{"name": "Black", "hex": "#000000", "image": ""}, {"name": "Royal", "hex": "#0033A0", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Orange", "hex": "#FF6900", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "Lime Green", "hex": "#A5CD39", "image": ""}]'::jsonb,null,'supplier',true,true,1.73,28,'indent_sea','Intex','https://www.intexglobal.com/product/melbourne-foldable-bag-with-gusset/');
