  ('IntexGlobal','FOLB10','Shopping Trolley Bags','shopping-trolley-bags-folb10','Bags','Tote Bags','The Shopping Trolley Bags are the ultimate reusable solution for efficient and organized grocery shopping. Designed to fit shopping trolleys, this set of four bags helps sort and carry groceries with ease while promoting sustainability.',250,true,false,'["Set of 4 Bags: Designed to keep groceries organized while shopping.", "Durable 80gsm Non-Woven Material: Strong and reusable for long-term use.", "Extended Handles: Makes carrying and lifting easier, perfect for shopping trolleys.", "Large Branding Area: Ideal for screen printing logos or promotional messages.", "Perfect for Grocery Shopping: Keeps food items sorted and reduces the need for excess plastic bags."]'::jsonb,'[{"name": "Size", "value": "44 x 35 x 21.5cm - 47 x 41 x 22cm - 54 x 49 x 24.5cm - 52 x 53 x 27.5cm"}]'::jsonb,'[{"name": "Black", "hex": "#000000", "image": ""}, {"name": "Royal", "hex": "#0033A0", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Orange", "hex": "#FF6900", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "Lime Green", "hex": "#A5CD39", "image": ""}]'::jsonb,null,'supplier',true,true,5.04,28,'indent_sea','Intex','https://www.intexglobal.com/product/shopping-trolley-bags/');
