  ('IntexGlobal','NWTB09','Non Woven Drawstring Bag','non-woven-drawstring-bag-nwtb09','Bags','Drawstring Bags','The Non-Woven Drawstring Bag is a budget-friendly and practical promotional item, ideal for trade shows, events, corporate giveaways, and retail promotions. Its lightweight design and large branding area make it a great way to showcase your logo while offering a reusable and eco-friendly product.',250,true,false,'["Durable Non-Woven Material: Strong yet lightweight for everyday use.", "Drawstring Closure: Securely keeps contents in place while allowing easy access.", "Spacious Interior: Ideal for carrying essentials like gym gear, books, or event materials.", "Large Branding Area: Perfect for screen printing logos, slogans, or promotional messages.", "Versatile Use: Great for sports events, schools, corporate giveaways, and travel."]'::jsonb,'[{"name": "Size", "value": "39 (w) x 49 (h) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb09/nwtb09-black.webp"}, {"name": "Bottle Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb09/nwtb09-bottle-green.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb09/nwtb09-green.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb09/nwtb09-grey.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb09/nwtb09-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb09/nwtb09-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/pr