  ('IntexGlobal','NWTB15','Shelly 6 Bottle Bag Wine Carrier','shelly-6-bottle-bag-wine-carrier-nwtb15','Bags','Wine Carriers','The Shelly 6 Bottle Bag is a practical and reusable promotional product, designed for carrying multiple bottles securely while maximizing brand exposure. Ideal for wineries, liquor stores, and event giveaways.',250,true,false,'["Durable 80gsm Non-Woven Material: Lightweight yet strong for reliable use.", "Reinforced Handles: Sturdy double handles ensure comfortable and safe carrying.", "Eco-Friendly & Reusable: A sustainable alternative to plastic bags, promoting green initiatives.", "Large Branding Area: Perfect for printing logos, slogans, or promotional messages."]'::jsonb,'[{"name": "Size", "value": "26(w) x 28 (h) x 18 (d)cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb15/nwtb15-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb15/nwtb15-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb15/nwtb15-orange.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb15/nwtb15-royal.webp"}]'::jsonb,null,'supplier',true,true,0.79,28,'indent_sea','Intex','https://www.intexglobal.com/product/shelly-6-bottle-bag/');
