  ('IntexGlobal','OCB100','Warm Knitted Acrylic Beanie Beany','warm-knitted-acrylic-beanie-beany-ocb100','Headwear','Beanies','Stay cozy and stylish with our Warm Knitted Acrylic Beanie , a winter essential made from 100% acrylic yarn. Designed to lock in warmth without sacrificing comfort, this soft-touch beanie is perfect for chilly days, outdoor events, or branded winter giveaways. Its stretch-fit knit offers a snug feel for most head sizes, making it a reliable staple for both fashion and function.',10,true,false,'["Made from 100% warm knitted acrylic.", "Soft-touch and stretch-fit comfort.", "Classic cuffed design.", "One size fits most.", "Ideal for outdoor wear, gifting, or branding."]'::jsonb,'[]'::jsonb,'[{"name": "Black", "hex": "#000000", "image": ""}, {"name": "Bottle Green", "hex": "#004225", "image": ""}, {"name": "Dark Marle", "hex": "#6E6E6E", "image": ""}, {"name": "Fluro Orange", "hex": "#FF6D00", "image": ""}, {"name": "Fluro Yellow", "hex": "#E8FF00", "image": ""}, {"name": "Grey", "hex": "#8A8D8F", "image": ""}, {"name": "Natural", "hex": "#E8DCC4", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/warm-knitted-acrylic-beanie/');
