  ('IntexGlobal','OCBBP1010','Cotton Canvas Tote Bag With Zipper Closure','cotton-canvas-tote-bag-with-zipper-closure-ocbbp1010','Bags','Tote Bags','The Cotton Canvas Tote Bag with Zipper Closure is a premium and reusable promotional tote, offering both durability and security for everyday use. Made from 280gsm unbleached canvas, it provides a sustainable and stylish alternative to plastic bags.',250,true,false,'["Premium 280gsm Unbleached Canvas: Strong, eco-friendly, and designed for long-lasting use.", "Zipper Closure: Keeps belongings secure, making it perfect for work, shopping, or travel.", "Base Gusset: Provides extra space and structure for carrying bulkier items.", "Spacious & Versatile: Ideal for groceries, corporate events, trade shows, or daily essentials.", "Reusable & Sustainable: Supports environmentally friendly initiatives by reducing single-use bags.", "Large Branding Area: Perfect for screen printing logos, slogans, or promotional artwork."]'::jsonb,'[{"name": "Size", "value": "46 (w) x 33 (h) x 13 (d) cm"}]'::jsonb,'[{"name": "Natural", "hex": "#E8DCC4", "image": ""}, {"name": "Black", "hex": "#000000", "image": ""}, {"name": "Royal", "hex": "#0033A0", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}]'::jsonb,null,'supplier',true,true,3.03,28,'indent_sea','Intex','https://www.intexglobal.com/product/cotton-canvas-tote-bag-with-zipper-closure/');
