  ('IntexGlobal','OCBH01','Cotton Bucket Hat','cotton-bucket-hat-ocbh01','Headwear','Bucket Hats','Introducing the Cotton Bucket Hat—Everyday Style with Natural Comfort. Crafted from 100% premium cotton, this classic bucket hat delivers breathable comfort and effortless style. Lightweight and durable, it’s the perfect companion for sunny days, outdoor events, travel, or relaxed weekend wear.',100,true,false,'["Made from 100% high-quality cotton for softness, breathability, and durability.", "Lightweight construction makes it ideal for warm weather and extended wear.", "Wide brim offers sun protection while maintaining a relaxed, laid-back look.", "Unstructured design ensures a casual fit that packs easily for travel.", "Perfect for casual outings, beach days, festivals, or branded promotions.", "Available in various colours and sizes to suit different styles and preferences."]'::jsonb,'[{"name": "Size", "value": "60cm Circumference"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbh01/ocbh01-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbh01/ocbh01-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbh01/ocbh01-red.webp"}, {"name": "Sky Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbh01/ocbh01-sky-blue.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbh01/ocbh01-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/cotton-bucket-hat/');
