  ('IntexGlobal','OCBMS115','Full Colour Printed Drawstring Backpack Drawstring Bag','full-colour-printed-drawstring-backpack-drawstring-bag-ocbms115','Bags','Drawstring Bags','The Full Colour Printed Drawstring Backpack is the ultimate promotional giveaway, offering a high-impact, fully customizable design that enhances brand visibility.',1,true,false,'["Full-Colour Custom Printing: High-quality, edge-to-edge sublimation print for vibrant and eye-catching branding.", "Durable 210D Nylon Fabric: Designed to withstand daily use while keeping items secure.", "Drawstring Closure: Easy access while ensuring contents stay safely inside.", "Spacious Interior: Ideal for carrying gym gear, school supplies, or event giveaways.", "Lightweight & Comfortable: Easy to carry, making it perfect for all ages.", "Eco-Friendly & Reusable: A sustainable and stylish alternative to disposable bags.", "Large Branding Area: Maximizes brand exposure with full-colour graphics and custom messaging."]'::jsonb,'[{"name": "Size", "value": "39 (w) x 49 (h) cm"}]'::jsonb,'[{"name": "Custom", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/full-colour-printed-drawstring-backpack/');
