  ('IntexGlobal','OCBMS152','Drawstring Cooler Pack Drawstring Bag','drawstring-cooler-pack-drawstring-bag-ocbms152','Bags','Drawstring Bags','The Drawstring Cooler Pack is a versatile and practical promotional item, combining the convenience of a drawstring bag with the insulation of a cooler. Perfect for outdoor events, sports teams, corporate giveaways, and picnics.',250,true,false,'["Durable 210D Nylon Material: Strong yet lightweight, designed for long-lasting use.", "Insulated Interior: Large insulated compartment keeps beverages and snacks cooler for longer.", "Drawstring Closure: Ensures easy access while keeping contents secure.", "External Pocket: Provides additional storage space for utensils, napkins, or small essentials.", "Spacious & Lightweight: Ideal for carrying lunch, drinks, or snacks on the go.", "Large Branding Area: Perfect for printing logos, slogans, or promotional designs."]'::jsonb,'[{"name": "Size", "value": "33 (w) x 39(h) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbms152/ocbms152-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbms152/ocbms152-blue.webp"}, {"name": "Burgundy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbms152/ocbms152-burgundy.webp"}, {"name": "Forest Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbms152/ocbms152-forest-green.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbms152/ocbms152-green.webp"}, {"name": "Navy Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbms152/ocbms152-navy-blue.webp"}, {"name": "Orang