  ('IntexGlobal','OCBOPEN8A','Vinyl Wrapped Paddle Style Bottle Opener','vinyl-wrapped-paddle-style-bottle-opener-ocbopen8a','Barware','Bottle Openers','The Vinyl Wrapped Paddle Style Bottle Opener is a bartender-favorite tool, designed for speed, efficiency, and durability. With its flat paddle design, this professional-grade opener ensures a firm grip and quick cap removal, making it ideal for bars, restaurants, events, and promotional giveaways.',250,true,false,'["Vinyl Wrapped Handle: Provides a comfortable, non-slip grip for easy handling.", "Paddle-Style Design: Perfect for quick and effortless bottle opening.", "Professional-Grade Tool: Ideal for bartenders, servers, and beverage enthusiasts.", "Compact & Portable: Fits easily in a pocket, apron, or behind the bar.", "Custom Branding Available: Can be printed or engraved with logos for promotional use."]'::jsonb,'[{"name": "Size", "value": "4 (w) x 18 (h) cm"}, {"name": "Durable Stainless Steel Core", "value": "Ensures long-lasting performance."}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbopen8a/ocbopen8a-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbopen8a/ocbopen8a-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbopen8a/ocbopen8a-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbopen8a/ocbopen8a-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbopen8a/ocbopen8a-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbopen8a/ocbop