  ('IntexGlobal','OCPB800','100% Recycled Paper Bag with Paper Webbed Handle','100-recycled-paper-bag-with-paper-webbed-handle-ocpb800','Bags','Paper Bags','The 100% Recycled Paper Bag with Paper Webbed Handle is an eco-friendly and durable packaging solution, designed for sustainability without compromising on strength. Crafted from 100% recycled paper, this bag provides a sturdy, reusable, and environmentally conscious alternative for retail, gifting, and everyday use.',250,true,false,'["Made from 100% Recycled Paper: A sustainable choice that reduces environmental impact.", "Strong Paper Webbed Handles: Provides enhanced durability and comfortable carrying.", "Practical & Versatile: Ideal for shopping, corporate giveaways, retail packaging, and events.", "Sturdy Construction: Designed to hold various goods securely.", "Large Branding Area: Perfect for screen printing, digital print, or custom artwork to showcase logos and promotional messages."]'::jsonb,'[{"name": "Size", "value": "29cm x 34cm x 9cm"}]'::jsonb,'[{"name": "Natural", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocpb800/ocpb800-main.webp"}]'::jsonb,null,'supplier',true,true,0.58,28,'indent_sea','Intex','https://www.intexglobal.com/product/100-recycled-paper-bag-with-paper-webbed-handle/');
