  ('IntexGlobal','OH4888','Plastic Hand Fan Supporter Gear','plastic-hand-fan-supporter-gear-oh4888','Outdoor & Lifestyle','Supporter Gear','The Plastic Hand Fan is a simple yet effective promotional item, ideal for keeping cool at outdoor events, concerts, sports games, and corporate giveaways. Made from durable plastic, this fan is lightweight, portable, and easy to use, making it a cost-effective branding tool.',250,true,false,'["Lightweight & Portable: Easy to carry and store.", "Effective Cooling Solution: Provides instant relief from heat at outdoor events.", "Ideal for Large-Scale Giveaways: Perfect for festivals, trade shows, and promotional campaigns.", "Custom Branding Available: Can be printed with logos or designs for promotional use."]'::jsonb,'[{"name": "Size", "value": "17cm Diameter"}, {"name": "Durable Plastic Construction", "value": "Ensures long-lasting use."}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh4888/oh4888-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh4888/oh4888-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh4888/oh4888-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh4888/oh4888-white.webp"}]'::jsonb,null,'supplier',true,true,0.92,28,'indent_sea','Intex','https://www.intexglobal.com/product/plastic-hand-fan/');
