  ('IntexGlobal','PAPB01GLL','Large Full Coloured Laminated Bag','large-full-coloured-laminated-bag-papb01gll','Bags','Paper Bags','The Large Full Colour Laminated Bag is a luxurious and durable promotional bag, designed to elevate corporate gifting, retail packaging, trade shows, and luxury events. Crafted from 210gsm laminated paper, this bag features a glossy finish for a polished look and strong rope handles for added durability and comfort.',1,true,false,'["Premium 210gsm Laminated Paper: Thick, durable, and designed for a sleek, high-end finish.", "Glossy Full-Colour Printing: High-impact branding with vibrant, edge-to-edge customization.", "Strong Rope Handles: Provides a sturdy grip for comfortable carrying.", "Spacious Design: Ideal for larger promotional materials, retail items, or corporate gifts.", "Large Branding Area: Perfect for full-colour printing of logos, marketing messages, or custom artwork for maximum visibility."]'::jsonb,'[{"name": "Size", "value": "Large : 38 (w) x 42 (h) x 10 (d) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/papb01gll/papb01gll-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/papb01gll/papb01gll-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/papb01gll/papb01gll-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/papb01gll/papb01gll-white.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/large-full-coloured-laminated-bag/');
