  ('IntexGlobal','PAPB01KWXL','Kraft Paper Bag White Extra Large Includes Twisted Paper Handle','kraft-paper-bag-white-extra-large-includes-twisted-paper-handle-papb01kwxl','Bags','Paper Bags','The Kraft Paper Bag White Extra Large is a durable and stylish packaging solution, ideal for retail, corporate gifting, trade shows, and promotional giveaways. Made from 128gsm kraft paper, this bag is strong, practical, and designed for easy carrying with its twisted paper handles.',250,true,false,'["Premium 128gsm Kraft Paper: Strong and sturdy for carrying bulkier items.", "Extra Large Size: Provides ample space for retail products, event materials, or corporate gifts.", "Twisted Paper Handles: Reinforced for durability and comfortable carrying.", "Clean White Finish: A sleek, professional look suitable for any occasion.", "Large Branding Area: Perfect for custom branding with logos and promotional messages."]'::jsonb,'[{"name": "Size", "value": "Extra large: 42 (w) x 45 (h) x 15 (d) cm"}]'::jsonb,'[{"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/papb01kwxl/papb01kwxl-main.webp"}]'::jsonb,null,'supplier',true,true,1.42,28,'indent_sea','Intex','https://www.intexglobal.com/product/kraft-paper-bag-white-extra-large-includes-twisted-paper-handle/');
