  ('IntexGlobal','PAT0604','Tin Gift Box: Rectangular With Window USB Flash Drive','tin-gift-box-rectangular-with-window-usb-flash-drive-pat0604','Tech','USB Flash Drives','The Tin Gift Box with a transparent window is a premium packaging solution designed to showcase your USB drives or small items with style. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Rectangular Tin Design: Durable and sleek, offering a polished and professional look.", "Transparent Window: Highlights the product inside, providing an elegant display for USB drives or other small items.", "Customizable Surface: Available for silkscreen printing, laser engraving, or full-color printing (FCP) at an additional charge.", "Versatile Use: Ideal for promotional gifts, corporate giveaways, or personal presentations."]'::jsonb,'[{"name": "Size", "value": "11.30 x 8.31 x 2.01 cm"}]'::jsonb,'[{"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/pat0604/pat0604-main.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/tin-gift-box-rectangular-with-window/');
