  ('IntexGlobal','PAT1003','Clear Plastic Case: Magnetic Short USB Flash Drive','clear-plastic-case-magnetic-short-usb-flash-drive-pat1003','Tech','USB Flash Drives','The Clear Plastic Magnetic Case is a modern and practical packaging option, ideal for showcasing USB drives or other compact items. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Compact Design: Short, sleek, and lightweight, perfect for portable and stylish presentations.", "Magnetic Closure: Ensures secure storage with a seamless and premium opening experience.", "Transparent Finish: Highlights the contents inside, providing a professional and elegant display.", "Customizable Surface: Available for screen printing or full-color printing (FCP) at an additional charge, ideal for branding or personalization."]'::jsonb,'[{"name": "Size", "value": "9cm W x 4.5cm H x 1.5cm L"}]'::jsonb,'[{"name": "Clear", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/pat1003/pat1003-main.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/clear-plastic-case-magnetic-short/');
