  ('IntexGlobal','PS1121','Grid Metal Pen','grid-metal-pen-ps1121','Pens','Metal Pens','Introducing the Grid Ballpen, a sophisticated writing tool that stands out with its unique grid-patterned design. Crafted from premium metal, this pen is not only functional but also an excellent promotional item that exudes style and professionalism.',100,true,false,'["Twist Action Mechanism: Smooth and reliable operation, offering ease of use with every twist.", "Elegant Grid Pattern: The lower barrel features a distinctive grid design, adding a touch of modern flair.", "Premium Metal Construction: Durable and designed for a polished, high-end appearance.", "Chrome Trim: Complements the grid design with an elegant finish.", "Refillable Black Ink: Equipped with high-quality, refillable black ink for long-term usability."]'::jsonb,'[{"name": "Size", "value": "14cm X 1.5cm"}]'::jsonb,'[{"name": "Bronze", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1121/ps1121-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/grid/');
