  ('IntexGlobal','PS1188','Large Neoprene Sublimated Pencil Case','large-neoprene-sublimated-pencil-case-ps1188','Office & Desk','Pencil Cases','Introducing the Large Neoprene Sublimated Pencil Case, a functional and stylish solution to keep your stationery organized. Made from durable neoprene, this pencil case features a secure black zippered closure and offers ample space for all your essentials.',250,true,false,'["Premium Neoprene Material: Flexible and durable, providing long-lasting protection for your pens, pencils, and other stationery items.", "Full-Colour Customization: Can be branded on both the front and back with vibrant, full-colour sublimation printing—perfect for promotional purposes or personalized designs.", "Secure Zippered Closure: Ensures your items are safely stored and easily accessible.", "Spacious Design: Large enough to hold a variety of stationery, making it ideal for students, professionals, or giveaways."]'::jsonb,'[{"name": "Size", "value": "32cm L x 10cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1188/ps1188-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1188/ps1188-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1188/ps1188-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1188/ps1188-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1188/ps1188-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1188/ps1188-purple.webp"}, {"name": "Red", "hex": "", "ima