  ('IntexGlobal','PS1201','Wheat Straw Lazarus 2 Eco Pen','wheat-straw-lazarus-2-eco-pen-ps1201','Pens','Eco Pens','Introducing the Wheat Straw Lazarus 2 Pen, a thoughtful blend of eco-conscious materials and modern design. Featuring a push/click action mechanism, this pen is perfect for those who want to make a sustainable choice without compromising on style or functionality.',100,true,true,'["Eco-Friendly Wheat Straw Barrel: Made from a sustainable wheat straw material, reducing environmental impact while maintaining durability.", "Push/Click Action: Easy-to-use mechanism for smooth and reliable writing.", "Modern Design: A sleek and stylish pen that combines practicality with sustainability.", "Customizable: Ideal for branding or corporate giveaways, with ample space for your logo or message."]'::jsonb,'[{"name": "Size", "value": "13.5cm x 1.5cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1201/ps1201-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1201/ps1201-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1201/ps1201-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1201/ps1201-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1201/ps1201-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1201/ps1201-yellow.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/wheat-straw-lazarus-2/');
