  ('IntexGlobal','PS1203','Wheat Straw Slimline Silver Eco Pen','wheat-straw-slimline-silver-eco-pen-ps1203','Pens','Eco Pens','Introducing the Wheat Straw Slimline Silver Pen, a sleek and eco-friendly writing tool designed for those who value sustainability and elegance. With its slim profile, it’s perfect for quick note-taking on the go and can easily be attached to your body for convenient access.',100,true,true,'["Eco-Friendly Wheat Straw Barrel: Made from sustainable wheat straw material, making it a great choice for environmentally conscious users.", "Slim and Compact Design: Its slim profile makes it easy to carry and perfect for on-the-go writing.", "Push/Click Action: Smooth and easy-to-use mechanism for quick, reliable writing.", "Silver Trimming: Adds a touch of sophistication to the pen''s design, making it both functional and stylish.", "Customizable: Ideal for promotional purposes with space for your logo or branding."]'::jsonb,'[{"name": "Size", "value": "14cm W X 1cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1203/ps1203-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1203/ps1203-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1203/ps1203-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1203/ps1203-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1203/ps1203-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/wheat-straw-slimline-silver/');
