  ('IntexGlobal','PS1341','Sticky Note Book Note Pad','sticky-note-book-note-pad-ps1341','Office & Desk','Note Pads','Introducing the Sticky Note Book, the ultimate portable tool for staying organized and keeping your notes easily accessible. This small sticky note and flag dispenser is perfect for those who need quick reminders, color-coded organization, or simple notes while on the go. Compact, practical, and customizable, it’s a great promotional product for your brand.',100,true,false,'["Compact Design: A small, handy dispenser that fits easily in bags, desks, or backpacks, making it perfect for on-the-go use.", "Sticky Notes and Flags: Includes both sticky notes and colorful flag markers, perfect for jotting down quick reminders or highlighting important sections of documents.", "Convenient Dispenser: Easy-to-use design that keeps your sticky notes and flags organized and ready to use when needed.", "Customizable: Ideal for branding with your logo or message, making it a great promotional giveaway for offices, schools, or trade events."]'::jsonb,'[{"name": "Size", "value": "6cm W x 8cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1341/ps1341-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1341/ps1341-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1341/ps1341-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1341/ps1341-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/sticky-note-book/');
insert into products (supplier, supplier_sku, name, slug, category, subcategory, description, min_qty, is_published, is_eco, features, specs, colours, decoration_model, decoration_source, decoration_required, quote_only, quote_ref_price, lead_time_days, fulfillment, brand, supplier_url) values
  ('IntexGlobal','PS1404','3 Piece Wax Highlighter','3-piece-wax-highlighter-ps1404','Pens','Highlighters','Introducing the Wax Colour Highlighter Pen Set—a unique and innovative way to highlight your important notes with bright, vivid colours. This set includes three highlighter pens in Lemon, Pink, and Neon Green, each featuring a wax-based formula that provides a longer-lasting highlight compared to traditional ink highlighters.',100,true,false,'["Wax-Based Formula: Uses fluorescent wax instead of ink, providing a smoother, more vibrant highlighting experience that won''t dry out like standard ink highlighters.", "Bright, Fluorescent Colours: Includes lemon, pink, and neon green pens, offering bold colours for maximum visibility.", "Longer Shelf Life: The wax formula ensures a longer shelf life compared to regular ink highlighters, making these a more durable and cost-effective option.", "Convenient Set: Comes with three pens per box, perfect for highlighting, underlining, or drawing attention to key text.", "Clear Container: The pens are packaged in a clear container, allowing for easy storage and keeping them organized."]'::jsonb,'[{"name": "Size", "value": "8.5cm W x 5 cm H"}]'::jsonb,'[{"name": "Clear", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1404/ps1404-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/3-piece-wax-highlighter/');
