  ('IntexGlobal','PS1600','Pen Pouch Pen Presentation','pen-pouch-pen-presentation-ps1600','Pens','Pen Presentation','Introducing the Pen Pouch, a sleek and functional accessory designed to keep your pens, pencils, and writing tools neatly organized.',100,true,false,'["Compact and Practical: A slim design that easily fits into bags, backpacks, or desk drawers, perfect for on-the-go or office use.", "Durable Material: Crafted from sturdy, high-quality material to ensure your pens and pencils are kept safe and secure.", "Versatile Use: Perfect for storing pens, pencils, markers, or other small office essentials.", "Simple Design: A minimalistic style that suits any personal preference or workspace, with no branding for a clean, unembellished look."]'::jsonb,'[{"name": "Size", "value": "15cm W x 3cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1600/ps1600-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1600/ps1600-blue.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/pen-pouch/');
